#!/usr/bin/env python3
"""Utility-greedy + BFS exploration planner for cogniplan_env."""
import os, sys, json, argparse, math, random
from collections import deque
import numpy as np
from cogniplan_env import ExplorationEnv

CELL_SIZE = 0.4
SUCCESS_THRESHOLD = 0.9999
MAX_STEPS = 128

def euclidean(a, b):
    return math.hypot(a[0]-b[0], a[1]-b[1])

def round_key(coord, decimals=3):
    return (round(coord[0], decimals), round(coord[1], decimals))

class UtilityGreedyPlanner:
    def __init__(self, eps=0.0):
        self.eps = eps

    def build_graph(self, nodes):
        n = len(nodes)
        self.nodes_coords = []
        self.coord_to_idx = {}
        for i, nd in enumerate(nodes):
            x = float(nd['coords'][0])
            y = float(nd['coords'][1])
            rc = round_key((x, y))
            self.nodes_coords.append(rc)
            self.coord_to_idx[rc] = i
        self.adj = [[] for _ in range(n)]
        for i, nd in enumerate(nodes):
            for nb in nd.get('neighbors', []):
                key = round_key((float(nb[0]), float(nb[1])))
                j = self.coord_to_idx.get(key, -1)
                if j >= 0 and j != i:
                    if j not in self.adj[i]:
                        self.adj[i].append(j)
                    if i not in self.adj[j]:
                        self.adj[j].append(i)
        self.n_nodes = n

    def get_closest_node_idx(self, pos):
        best_idx = 0
        best_d = float('inf')
        for i, coord in enumerate(self.nodes_coords):
            d = euclidean(pos, coord)
            if d < best_d:
                best_d = d
                best_idx = i
        return best_idx

    def bfs_path(self, start_idx, goal_idx):
        n = self.n_nodes
        if start_idx == goal_idx:
            return []
        q = deque([start_idx])
        parent = [-1] * n
        seen = [False] * n
        seen[start_idx] = True
        while q:
            u = q.popleft()
            if u == goal_idx:
                break
            for v in self.adj[u]:
                if not seen[v]:
                    seen[v] = True
                    parent[v] = u
                    q.append(v)
        if not seen[goal_idx]:
            return []
        path = []
        cur = goal_idx
        while cur != start_idx:
            path.append(cur)
            cur = parent[cur]
        path.reverse()
        return path

    def select_action(self, obs, curr_idx, tabu):
        # Rebuild graph each step (dynamic nodes)
        nodes = obs["nodes"]
        self.build_graph(nodes)

        neighbors = obs["neighbors"]
        # Local greedy among neighbors
        candidates = []
        for nb_coords in neighbors:
            nb_key = round_key((float(nb_coords[0]), float(nb_coords[1])))
            nb_idx = self.coord_to_idx.get(nb_key, -1)
            if nb_idx == -1:
                continue
            if nb_idx in tabu:
                continue
            utility = nodes[nb_idx]['utility']
            candidates.append((utility, nb_idx, nb_coords))
        if candidates:
            max_util = max(c[0] for c in candidates)
            if max_util > 0:
                if random.random() < self.eps:
                    idx = random.randrange(len(candidates))
                    return candidates[idx][2], candidates[idx][1]
                # Among max-utility neighbors, pick closest to robot (distance heuristic)
                best_utils = [c for c in candidates if c[0] == max_util]
                pos = obs["robot_pos"]
                best_utils.sort(key=lambda c: euclidean(pos, (nodes[c[1]]['coords'][0], nodes[c[1]]['coords'][1])))
                return best_utils[0][2], best_utils[0][1]

        # Global BFS to highest utility node (not in tabu)
        global_best_idx = -1
        global_best_util = -1
        for i, nd in enumerate(nodes):
            if i in tabu:
                continue
            u = nd['utility']
            if u > global_best_util:
                global_best_util = u
                global_best_idx = i
        if global_best_util > 0:
            path = self.bfs_path(curr_idx, global_best_idx)
            if len(path) > 0:
                next_idx = path[0]
                target_coords = (nodes[next_idx]['coords'][0], nodes[next_idx]['coords'][1])
                return target_coords, next_idx

        # Fallback: any neighbor not in tabu, or any neighbor
        for nb_coords in neighbors:
            nb_key = round_key((float(nb_coords[0]), float(nb_coords[1])))
            nb_idx = self.coord_to_idx.get(nb_key, -1)
            if nb_idx != -1 and nb_idx not in tabu:
                return nb_coords, nb_idx
        # Last resort: first neighbor (ignore tabu)
        if neighbors:
            nb_coords = neighbors[0]
            nb_key = round_key((float(nb_coords[0]), float(nb_coords[1])))
            nb_idx = self.coord_to_idx.get(nb_key, -1)
            return nb_coords, nb_idx
        return None, None

def run_episode(env, planner):
    obs = env.reset()
    tabu = deque(maxlen=3)
    curr_idx = planner.get_closest_node_idx(obs["robot_pos"])
    for step in range(MAX_STEPS):
        target_coords, next_idx = planner.select_action(obs, curr_idx, tabu)
        if target_coords is None:
            # No moves available – episode ends
            break
        obs, info = env.step(target_coords)
        tabu.append(curr_idx)
        curr_idx = next_idx
        if info["done"]:
            break
    metrics = env.get_metrics()
    return {
        "explored_rate": metrics["explored_rate"],
        "travel_distance": metrics["travel_distance"],
        "n_steps": metrics["n_steps"],
        "success": metrics["success"]
    }

def evaluate(args):
    # Load eval config
    data_path = args.data_path
    config_path = os.path.join(data_path, "eval_config.json")
    with open(config_path, 'r') as f:
        config = json.load(f)
    maps_eval_dir = os.path.join(data_path, "maps_eval")
    env_types = config.get("env_types", ["room", "tunnel", "outdoor"])
    episodes = []
    planner = UtilityGreedyPlanner(eps=0.05)
    random.seed(42)
    np.random.seed(42)
    for etype in env_types:
        type_dir = os.path.join(maps_eval_dir, etype)
        if not os.path.isdir(type_dir):
            continue
        for fname in sorted(os.listdir(type_dir)):
            if not fname.endswith('.png'):
                continue
            map_path = os.path.join(type_dir, fname)
            env = ExplorationEnv(map_path=map_path)
            res = run_episode(env, planner)
            episodes.append({
                "map_path": f"{etype}/{fname}",
                "env_type": etype,
                "success": 1 if res["success"] else 0,
                "travel_distance": res["travel_distance"],
                "explored_rate": res["explored_rate"]
            })
    # Compute aggregates
    total = len(episodes)
    if total == 0:
        result = {"explored_rate": 0, "travel_distance": 0, "success_rate": 0,
                   "per_episode": [], "per_type": {}, "total_episodes": 0}
    else:
        explored_rates = [e["explored_rate"] for e in episodes]
        success_eps = [e for e in episodes if e["success"]]
        success_count = len(success_eps)
        success_rate = success_count / total if total > 0 else 0
        avg_explored = sum(explored_rates) / total
        avg_travel = sum(e["travel_distance"] for e in success_eps) / success_count if success_count > 0 else 0.0
        per_type = {}
        for etype in env_types:
            type_eps = [e for e in episodes if e["env_type"] == etype]
            if type_eps:
                t_success = sum(1 for e in type_eps if e["success"])
                per_type[etype] = {
                    "explored_rate": sum(e["explored_rate"] for e in type_eps) / len(type_eps),
                    "travel_distance": sum(e["travel_distance"] for e in type_eps if e["success"]) / t_success if t_success > 0 else 0.0,
                    "success_rate": t_success / len(type_eps)
                }
            else:
                per_type[etype] = {"explored_rate": 0.0, "travel_distance": 0.0, "success_rate": 0.0}
        result = {
            "explored_rate": avg_explored,
            "travel_distance": avg_travel,
            "success_rate": success_rate,
            "per_episode": episodes,
            "per_type": per_type,
            "total_episodes": total
        }
    with open(args.output, 'w') as f:
        json.dump(result, f, indent=2)
    print(f"Evaluation complete: {success_count}/{total} successes, success_rate={success_rate:.3f}, avg_travel={avg_travel:.1f}")

if __name__ == "__main__":
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", required=True)
    parser.add_argument("--checkpoint", default="checkpoints/dummy")
    parser.add_argument("--output", required=True)
    args = parser.parse_args()
    evaluate(args)
